import React, { useState, useEffect } from "react";
import {
  SectionWrapper,
  Wrapper,
} from "../../components/Styles/RegisterStyles";
import axios from "axios";
import DataTable from "react-data-table-component";
import { Link, useParams } from "react-router-dom";
import { FaEllipsisV, FaEye, FaHistory } from "react-icons/fa";
import SideBar from '../../components/Investor/social/SideBar';
import TopBar from '../../components/Investor/social/TopBar';
import { DataRoomSection } from "../../components/Styles/DataRoomStyle.js";
import { BackButton } from "../../components/Styles/GlobalStyles.js";
import { ArrowLeft } from "lucide-react";
import { useNavigate } from "react-router-dom";
import CurrencyFormatter from "../../components/CurrencyFormatter.jsx";
import DangerAlertPopup from "../../components/Admin/DangerAlertPopup.jsx";
import ChatMessageModal from "../../components/social/company/ChatMessageModal.jsx";
// ✅ CSS Styles for Dropdown Visibility
const dropdownStyles = `
  .tb-box {
    overflow: visible !important;
  }

  .rdt_Table {
    overflow: visible !important;
  }

  .rdt_TableRow {
    overflow: visible !important;
    position: relative;
  }

  .rdt_TableCell {
    overflow: visible !important;
  }

  .dropdown-menu {
    position: absolute !important;
    z-index: 99999 !important;
  }

  /* For the table container */
  .datatb-report {
    overflow: visible !important;
  }

  /* Ensure the action cell can contain absolute positioned dropdown */
  .rdt_TableCell:last-child {
    overflow: visible !important;
    position: relative;
  }
`;

function CapitalRoundList() {
  const [open, setOpen] = useState(null);

  const navigate = useNavigate();
  document.title = "Company New Invitation - Investor";
  const [messagesuccessError, setmessagesuccessError] = useState("");
  const [errr, seterrr] = useState(false);
  const customStyles = {
    table: {
      style: {
        minWidth: "100%",
        boxShadow: "0px 3px 12px rgb(0 0 0 / 16%)",
        borderRadius: "12px",
        overflow: "visible",
      },
    },
    headCells: {
      style: {
        backgroundColor: "#efefef !important",
        fontWeight: "600",
        fontSize: "0.9rem",
        color: "#000 !important",
        whiteSpace: "nowrap",
        overflow: "visible",
      },
    },
    cells: {
      style: {
        whiteSpace: "nowrap",
        textOverflow: "ellipsis",
        backgroundColor: "#fff !important",
        overflow: "visible",
      },
    },
    rows: {
      style: {
        fontSize: "0.8rem",
        fontWeight: "500",
        position: "relative",
        "&:hover": {
          backgroundColor: "#e8f0fe",
        },
      },
      stripedStyle: {
        backgroundColor: "#f4f6f8",
      },
    },
    pagination: {
      style: {
        backgroundColor: "#fafafa",
        padding: "12px 16px",
      },
    },
  };
  var apiURLround = "https://capavate.com/api/user/investorround/";
  var apiURL = "https://capavate.com/api/user/capitalround/";

  const storedUsername = localStorage.getItem("InvestorData");
  const userLogin = JSON.parse(storedUsername);
  const access_token = userLogin?.access_token;
  const [searchText, setSearchText] = useState("");
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [records, setRecords] = useState([]);
  const [selectedChatUser, setSelectedChatUser] = useState(null);
  const [showChatModal, setShowChatModal] = useState(false);
  var invname = userLogin?.first_name + " " + userLogin?.last_name;
  const currentUser = {
    id: userLogin.id,
    type: "investor",
    name: invname,
    email: userLogin.email,
  };
  const handleMessage = (invid, name, email, logo) => {
    setSelectedChatUser({
      id: invid,
      type: "investor",
      name: name,
      role: "investor",
      email: email,
      avatar: logo
    });
    setShowChatModal(true);
  };
  useEffect(() => {
    getInvestorCapitalMotionlist();
  }, []);

  const getInvestorCapitalMotionlist = async () => {
    let formData = {
      investor_id: userLogin.id,

    };

    try {
      const res = await axios.post(
        apiURL + "getInvestorCapitalMotionlist",
        formData,
        {
          headers: {
            Accept: "application/json",
            "Content-Type": "application/json",
            'Authorization': `Bearer ${access_token}`,
          },
        }
      );
      console.log(res.data.results);
      setRecords(res.data.results);
    } catch (err) {
      console.error("Error fetching data:", err);
    }
  };

  const filteredData = React.useMemo(() => {
    if (!records || records.length === 0) return [];

    if (!searchText || searchText.trim() === "") {
      return records;
    }

    const search = searchText.toLowerCase().trim();

    return records.filter((item) => {
      return (
        (item.company_name || "").toLowerCase().includes(search) ||
        (item.nameOfRound || "").toLowerCase().includes(search) ||
        (item.shareClassType || "").toLowerCase().includes(search) ||
        (item.instrumentType || "").toLowerCase().includes(search) ||
        (item.roundStatus || "").toLowerCase().includes(search) ||
        (item.company_city || "").toLowerCase().includes(search) ||
        (item.company_country || "").toLowerCase().includes(search) ||
        (item.roundsize || "").toLowerCase().includes(search)
      );
    });
  }, [records, searchText]);

  function formatCurrentDate(input) {
    const date = new Date(input);
    if (isNaN(date)) return "";

    const months = [
      "January", "February", "March", "April", "May", "June",
      "July", "August", "September", "October", "November", "December"
    ];

    const day = date.getDate();
    const month = months[date.getMonth()];
    const year = date.getFullYear();

    const getOrdinal = (n) => {
      if (n >= 11 && n <= 13) return "th";
      switch (n % 10) {
        case 1: return "st";
        case 2: return "nd";
        case 3: return "rd";
        default: return "th";
      }
    };

    return `${month} ${day}${getOrdinal(day)}, ${year}`;
  }

  const handleBackClick = () => {
    navigate("/investor/company-list");
  };

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = () => {
      if (open !== null) {
        setOpen(null);
      }
    };
    document.addEventListener("click", handleClickOutside);
    return () => {
      document.removeEventListener("click", handleClickOutside);
    };
  }, [open]);

  const toggleDropdown = (rowId, e) => {
    e.stopPropagation();
    setOpen(open === rowId ? null : rowId);
  };
  const [fundingroundMessage, setfundingroundMessage] = useState("");
  const [corpId, setcorpId] = useState('')
  const handleArchived = async (id) => {
    setcorpId(id);
    setfundingroundMessage("Are you sure you want to archive this invitation?");

  };
  const handlefundingRoundConfirm = async () => {

    try {
      const res = await axios.post(
        apiURLround + "archiveInvitation",
        {
          company_investor_id_id: corpId,
          investor_id: userLogin.id,
        },
        {
          headers: {
            Accept: "application/json",
            "Content-Type": "application/json",
            'Authorization': `Bearer ${access_token}`,
          },
        }
      );

      if (res.data.status) {
        setmessagesuccessError("Archived successfully.");
        seterrr(false);

        // ── REFRESH DATA ──
        getInvestorCapitalMotionlist(); // replace with your actual list refresh function

        setTimeout(() => {
          setfundingroundMessage('')
          setmessagesuccessError('');
        }, 3000);

      } else {
        setfundingroundMessage('')
        setmessagesuccessError(res.data.message || "Failed to archive invitation.");
        seterrr(false);
      }

    } catch (err) {
      setfundingroundMessage('')
      setmessagesuccessError("Something went wrong. Please try again.");
      seterrr(false);
    }
  }
  return (
    <>
      {/* ✅ Inject CSS Styles */}
      <style>{dropdownStyles}</style>

      <main>
        <div className='d-flex align-items-start gap-0'>
          <SideBar />
          <div className='d-flex flex-grow-1 flex-column gap-0'>
            <TopBar />
            <SectionWrapper className="d-block p-md-4 p-3">
              <div className="container-fluid">
                <DataRoomSection className="d-flex flex-column gap-3">
                  <div className="titleroom flex-wrap gap-3 d-flex justify-content-between align-items-center border-bottom pb-3">
                    <BackButton
                      type="button"
                      className="backbtn"
                      onClick={handleBackClick}
                    >
                      <ArrowLeft size={16} className="me-1" /> back
                    </BackButton>
                    <h4 className="mainh1">Investor Round List</h4>
                  </div>
                  {fundingroundMessage && (
                    <DangerAlertPopup
                      message={fundingroundMessage}
                      onConfirm={handlefundingRoundConfirm}
                      onCancel={() => {
                        setfundingroundMessage("");
                      }}
                    />
                  )}
                  {messagesuccessError && (
                    <div
                      className={`flex items-center justify-between gap-3 shadow-lg ${errr ? "error_pop" : "success_pop"
                        }`}
                    >
                      <div className="d-flex align-items-center gap-2">
                        <span className="d-block">{messagesuccessError}</span>
                      </div>

                      <button
                        type="button"
                        className="close_btnCros"
                        onClick={() => setmessagesuccessError("")}
                      >
                        ×
                      </button>
                    </div>
                  )}
                  <div className="d-flex justify-content-end p-0">
                    <input
                      type="search"
                      placeholder="Search Here..."
                      className="textarea_input"
                      value={searchText}
                      onChange={(e) => setSearchText(e.target.value)}
                      style={{
                        padding: "10px",
                        width: "100%",
                        maxWidth: "200px",
                        fontSize: "14px",
                      }}
                    />
                  </div>

                  <div className="d-flex flex-column justify-content-between align-items-start tb-box">
                    <DataTable
                      customStyles={customStyles}
                      columns={[
                        {
                          name: "Company Name",
                          selector: (row) => row.company_name,
                          sortable: true,
                          cell: (row) => <span>{row.company_name}</span>,
                        },
                        {
                          name: "City",
                          selector: (row) => row.company_city,
                          sortable: true,
                          cell: (row) => <span>{row.company_city}</span>,
                        },
                        {
                          name: "Round Status",
                          selector: (row) => row.dateroundclosed,
                          sortable: true,
                          cell: (row) => {
                            const isActive = row.roundStatus === "ACTIVE";
                            let displayText;

                            if (isActive) {
                              displayText = "Open Round (Active)";
                            } else if (!row.dateroundclosed) {
                              displayText = "No Active Round";
                            } else {
                              displayText = `No Active Round`;
                            }

                            return (
                              <span
                                style={{
                                  padding: "4px 12px",
                                  borderRadius: "12px",
                                  fontWeight: "600",
                                  color: isActive ? "#065f46" : "#b91c1c",
                                  backgroundColor: isActive ? "#d1fae5" : "#fee2e2",
                                  fontSize: "12px",
                                  display: "inline-block",
                                }}
                              >
                                {displayText}
                              </span>
                            );
                          },
                        },
                        {
                          name: "Investment History",
                          selector: (row) => row.company_city,
                          sortable: true,
                          cell: (row) => (
                            <span style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>

                              <Link
                                to={`/investor/company/capital-round-list/history/${row.company_id}/${row.id}`} target="_blank"
                                className="dropdown-item"
                                style={{
                                  display: "flex",
                                  alignItems: "center",
                                  gap: "8px",
                                  padding: "8px 16px",
                                  color: "#333",
                                  textDecoration: "none",
                                }}
                                onClick={() => setOpen(null)}
                              >
                                <FaEye style={{ cursor: 'pointer', color: '#CC0000' }} />
                              </Link>
                            </span>
                          ),
                        },
                        {
                          name: "Company Overview & Deal Terms",
                          sortable: true,
                          cell: (row) => (
                            <span style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>

                              <Link
                                to={`/investor/company/company-round-list/view/${row.company_id}/${row.id}`} target="_blank"
                                className="dropdown-item"
                                style={{
                                  display: "flex",
                                  alignItems: "center",
                                  gap: "8px",
                                  padding: "8px 16px",
                                  color: "#333",
                                  textDecoration: "none",
                                }}
                                onClick={() => setOpen(null)}
                              >
                                <FaEye style={{ cursor: 'pointer', color: '#CC0000' }} />
                              </Link>
                            </span>
                          ),
                        },


                        {
                          name: "Actions",
                          cell: (row) => (
                            <div
                              className="position-relative"
                              style={{ position: "relative", zIndex: 9999 }}
                            >
                              <button
                                className="btn btn-light btn-sm"
                                onClick={(e) => toggleDropdown(row.id, e)}
                                style={{
                                  border: "1px solid #ddd",
                                  borderRadius: "6px",
                                  padding: "4px 8px",
                                  cursor: "pointer",
                                }}
                              >
                                <FaEllipsisV />
                              </button>

                              {open === row.id && (
                                <div
                                  className="dropdown-menu show"
                                  style={{
                                    position: "absolute",
                                    top: "100%",
                                    right: 0,
                                    left: "auto",
                                    minWidth: "220px",
                                    zIndex: 99999,
                                    borderRadius: "8px",
                                    background: "#fff",
                                    boxShadow: "0 4px 12px rgba(0,0,0,0.15)",
                                    display: "block",
                                    marginTop: "4px",
                                  }}
                                >


                                  <div className="dropdown-divider" style={{ margin: "4px 0" }}></div>
                                  <Link
                                    to=""
                                    className="dropdown-item"
                                    style={{
                                      display: "flex",
                                      alignItems: "center",
                                      gap: "8px",
                                      padding: "8px 16px",
                                      color: "#333",
                                      textDecoration: "none",
                                    }}
                                    onClick={() => handleArchived(row.company_investor_id)}
                                  >
                                    <FaHistory /> Archive Company
                                  </Link>
                                  <Link
                                    to=""
                                    className="dropdown-item"
                                    style={{
                                      display: "flex",
                                      alignItems: "center",
                                      gap: "8px",
                                      padding: "8px 16px",
                                      color: "#333",
                                      textDecoration: "none",
                                    }} title="Chat Message"
                                    onClick={() => handleMessage(
                                      row.shared_by_company_id,
                                      row.company_name,
                                      row.company_email,
                                      row.company_logo_url
                                    )}
                                  >
                                    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                      <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
                                    </svg> Message
                                  </Link>
                                </div>
                              )}
                            </div>
                          ),
                          ignoreRowClick: true,
                          allowOverflow: true,
                          button: true,
                          width: "100px",
                        },
                      ]}
                      className="datatb-report"
                      data={filteredData}
                      pagination
                      highlightOnHover
                      striped
                      responsive
                      paginationRowsPerPageOptions={[10, 25, 50, 100]}
                      paginationComponentOptions={{
                        rowsPerPageText: "Rows per page:",
                        rangeSeparatorText: "of",
                        noRowsPerPage: false,
                        selectAllRowsItem: false,
                      }}
                    />
                  </div>
                </DataRoomSection>
              </div>
            </SectionWrapper>
          </div>
        </div>
      </main>
      {showChatModal && selectedChatUser && (
        <ChatMessageModal
          onClose={() => {
            setShowChatModal(false);
            setSelectedChatUser(null);
          }}
          currentUser={currentUser}
          selectedUser={selectedChatUser}
        />
      )}
    </>
  );
}

export default CapitalRoundList;